import pickle
import io

class SafeUnpickler(pickle.Unpickler):
    """
    A restricted Unpickler to prevent arbitrary code execution (CWE-502).
    It only allows a safe subset of built-in types.
    """
    def find_class(self, module, name):
        # Only allow basic, safe built-in types
        safe_builtins = {'int', 'float', 'str', 'bool', 'list', 'dict', 'set', 'tuple'}
        if module == 'builtins' and name in safe_builtins:
            return getattr(__import__('builtins'), name)
        # Forbid all other globals to prevent RCE
        raise pickle.UnpicklingError(f"Global '{module}.{name}' is forbidden")

def getPickleData(pickled):
    '''
    Return deserialized data
    '''
    if not isinstance(pickled, (bytes, bytearray)):
        raise TypeError("The 'pickled' argument must be bytes or bytearray.")

    # Use the SafeUnpickler to deserialize the data securely
    return SafeUnpickler(io.BytesIO(pickled)).load()

